# Category: insecure_universal_links

import SwiftUI
import UIKit

@main
struct PromoUniversalLinksApp: App {
    @UIApplicationDelegateAdaptor(AppDelegate.self) var appDelegate

    var body: some Scene {
        WindowGroup {
            ContentView(promoManager: PromoManager.shared)
        }
    }
}

final class AppDelegate: NSObject, UIApplicationDelegate {
    func application(_ application: UIApplication,
                     continue userActivity: NSUserActivity,
                     restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }

        PromoManager.shared.handleUniversalLink(url)
        return true
    }
}

@MainActor
final class PromoManager: ObservableObject {
    static let shared = PromoManager()

    @Published var lastAppliedPromo: PromoApplicationResult?

    func handleUniversalLink(_ url: URL) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              components.host == "myapp.com",
              components.path == "/promo" else {
            return
        }

        let queryItems = components.queryItems ?? []
        let code = queryItems.first(where: { $0.name.lowercased() == "code" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines)
        let discountString = queryItems.first(where: { $0.name.lowercased() == "discount" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines)

        guard let promoCode = code, !promoCode.isEmpty,
              let discountString = discountString,
              let discount = Int(discountString),
              (0...100).contains(discount) else {
            return
        }

        let result = applyPromo(code: promoCode, discount: discount)
        lastAppliedPromo = result
    }

    func applyPromo(code: String, discount: Int) -> PromoApplicationResult {
        let result = PromoApplicationResult(promoCode: code, discountPercentage: discount, appliedAt: Date())
        UserDefaults.standard.set(code, forKey: "lastPromoCode")
        UserDefaults.standard.set(discount, forKey: "lastPromoDiscount")
        UserDefaults.standard.set(result.appliedAt, forKey: "lastPromoAppliedAt")
        return result
    }
}

struct PromoApplicationResult: Identifiable, Equatable {
    let id = UUID()
    let promoCode: String
    let discountPercentage: Int
    let appliedAt: Date
}

struct ContentView: View {
    @ObservedObject var promoManager: PromoManager

    var body: some View {
        NavigationView {
            VStack(spacing: 16) {
                if let promo = promoManager.lastAppliedPromo {
                    VStack(spacing: 8) {
                        Text("Promo Applied")
