                        Text("Code: \(promo.promoCode)")
                        Text("Discount: \(promo.discountPercentage)%")
                        Text("Applied at: \(promo.appliedAt.formatted(date: .abbreviated, time: .shortened))")
                    }
                    .padding()
                } else {
                    Text("Waiting for promotional universal link...")
                        .foregroundColor(.secondary)
                }

                Button("Apply Sample Promo Link") {
                    if let url = URL(string: "https://myapp.com/promo?code=XYZ&discount=50") {
                        PromoManager.shared.handleUniversalLink(url)
                    }
                }
                .buttonStyle(.borderedProminent)
            }
            .padding()
            .navigationTitle("Promotions")
        }
        .onAppear {
            if let code = UserDefaults.standard.string(forKey: "lastPromoCode"),
               let discount = UserDefaults.standard.object(forKey: "lastPromoDiscount") as? Int,
               let appliedAt = UserDefaults.standard.object(forKey: "lastPromoAppliedAt") as? Date {
                promoManager.lastAppliedPromo = PromoApplicationResult(promoCode: code, discountPercentage: discount, appliedAt: appliedAt)
            }
        }
